// Override `messages` to attach an image part alongside the text.
prompt(null, {
  model: 'gpt-4o-mini',
  messages: [
    {
      role: 'user',
      content: [
        { type: 'text', text: 'Describe what is happening in this image.' },
        { type: 'image_url', image_url: { url: $.data.imageUrl } },
