Conversation (Legacy).code:
// Multi-turn chat via Chat Completions. Provide the full message history.
// `prompt`'s first arg is ignored when `messages` is overridden.
prompt(null, {
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: 'You are a concise assistant.' },
    ...($.state.history || []),
    { role: 'user', content: $.data.userMessage },
  ],
  temperature: 0.5,
});

Extract Structured Data.code:
// Extract structured fields via the Responses API, constrained to a JSON schema.
deepResearch(
  `Extract the contact details from the message below.\n\nMESSAGE:\n${$.data.message}`,
  {
    model: 'gpt-4o',
    tools: [],
    text: {
      format: {
        type: 'json_schema',
        name: 'contact',
        schema: {
          type: 'object',
          properties: {
            name:  { type: 'string' },
            email: { type: 'string' },
            phone: { type: 'string' },
          },
          required: ['name'],
          additionalProperties: false,
        },
      },
    },
  }
);

